export const TypographyDemo = (): Html => {
  const h = html<never>()

  return h.article(
    [h.Class('max-w-3xl')],
    [
      h1View(h),
      paragraphView(h),
      h2View(h),
      paragraphView(h),
      h3View(h),
      blockquoteView(h),
      h4View(h),
      listView(h),
      tableView(h),
    ],
  )
}

